# Codey onboard idle loop generated by codeyx
# Stop by pressing button A, or by restarting Codey.

import codey
import time

EYES = '00003c7e7e3c000000003c7e7e3c0000'
BLINK = '0000001818000000000000181800000000'
LOOK_L = '003c7e7e3c00000000003c7e7e3c000000'
LOOK_R = '0000003c7e7e3c00000000003c7e7e3c'

codey.led.show(0, 60, 180)

while True:
    for img, delay in [
        (EYES, 1.7),
        (BLINK, 0.12),
        (EYES, 0.9),
        (LOOK_L, 0.7),
        (EYES, 1.3),
        (BLINK, 0.10),
        (EYES, 0.9),
        (LOOK_R, 0.7),
        (EYES, 1.2),
    ]:
        codey.display.show_image(img)
        time.sleep(delay)
        if codey.button_a.is_pressed():
            codey.display.show_image(EYES)
            codey.led.show(0, 60, 180)
            raise SystemExit
